Exit fullscreen mode

@if (isLoading()) {
<p>Loading…</p>
} @else if (error()) {
<p class="error">{{ error() }}</p>
} @else {
@for (task of tasks(); track task.id) {
<li>{{ task.title }}</li>
}
}

