Exit fullscreen mode

Place it once in AppComponent so it is always present regardless of which route is active:

// app.component.ts
@Component({
selector: 'app-root',
standalone: true,
imports: [RouterOutlet, ErrorModalComponent],
template: `
<router-outlet />
<app-error-modal />
`,
})
export class AppComponent {}

